#!/usr/bin/env node
/**
 * tests/contracts/wild-blocks-deep-r.test.mjs
 *
 * UQ-DEEP-R regression suite — pins 4 systemic patterns fixed across 11
 * wild blocks (2026-06-24). Generated by forensic agent A audit nad
 * cellom wild-block katalogom posle UQ-DEEP-Q expanding-wild fix-eva.
 *
 * Patterns:
 *   P2 (features[].config inheritance) — 9 blocks: stickyWild, walkingWild,
 *       wildReel, mysteryWildReveal, wildCollisionMultiplier,
 *       cascadingWildPersistence, fsExpansionWilds, wildTriggerHoldAndWin,
 *       megaWildCluster, walkingWildStepper
 *   P3 (H&W gate add) — 3 blocks: wildCollisionMultiplier,
 *       cascadingWildPersistence, mysteryWildReveal
 *   P4 (FSM phase /^FS_/ regex) — 3 blocks: stickyWild, walkingWild, wildReel
 *   P6 (data-symbol + window.GRID + symbolOverride emit) — 5 blocks:
 *       stickyWild, randomWildBurst, fsExpansionWilds, megaWildCluster,
 *       cascadingWildPersistence
 *   P5 (DOM fallback for grid scan) — 1 block: fsExpansionWilds
 *
 * Exit 0 PASS, 1 FAIL.
 */
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { readFileSync } from 'node:fs';

const __filename = fileURLToPath(import.meta.url);
const REPO = resolve(dirname(__filename), '..', '..');

let pass = 0, fail = 0;
const failures = [];

function assert(cond, msg) { if (!cond) throw new Error(msg || 'assertion failed'); }

async function test(name, fn) {
  try {
    await fn();
    pass++;
    console.log(`  ✓ ${name}`);
  } catch (e) {
    fail++;
    failures.push({ name, error: e.message });
    console.log(`  ✗ ${name} — ${e.message}`);
  }
}

console.log('═══ wild-blocks-deep-r.test.mjs ═══');

/* ────────────────────────────────────────────────────────────────────── */
/* P4 — FSM phase regex (3 blocks). */

await test('P4 stickyWild: /^FS_/ regex in phase check', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/stickyWild.mjs'), 'utf8');
  assert(src.includes('/^FS_/.test(ph)'), 'regex test missing');
  const code = src.replace(/\/\*[\s\S]*?\*\//g, '');
  assert(!/ph === 'FS_ACTIVE' \|\| ph === 'FS_INTRO'/.test(code),
    'old strict equality still present');
});

await test('P4 walkingWild: /^FS_/ regex in phase check', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/walkingWild.mjs'), 'utf8');
  assert(src.includes('/^FS_/.test(ph)'), 'regex test missing');
});

await test('P4 wildReel: /^FS_/ regex in phase check', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/wildReel.mjs'), 'utf8');
  assert(src.includes('/^FS_/.test(ph)'), 'regex test missing');
});

/* ────────────────────────────────────────────────────────────────────── */
/* P2 — features[].config inheritance (run live resolveConfig). */

const FEATURE_INHERIT_CASES = [
  { mod: 'stickyWild.mjs',           kind: 'sticky_wild',            knob: 'wildSymbolId', val: 'WX' },
  { mod: 'walkingWild.mjs',          kind: 'walking_wild',           knob: 'wildSymbolId', val: 'WX' },
  { mod: 'wildReel.mjs',             kind: 'wild_reel',              knob: 'wildSymbolId', val: 'WX' },
  { mod: 'mysteryWildReveal.mjs',    kind: 'mystery_wild_reveal',    knob: 'wildSymbolId', val: 'WX' },
  { mod: 'wildCollisionMultiplier.mjs', kind: 'wild_collision_multiplier', knob: 'wildSymbolId', val: 'WX' },
  { mod: 'cascadingWildPersistence.mjs', kind: 'cascading_wild_persistence', knob: 'wildSymbolId', val: 'WX' },
  { mod: 'fsExpansionWilds.mjs',     kind: 'fs_expansion_wilds',     knob: 'wildSymbol',   val: 'WX' },
  { mod: 'wildTriggerHoldAndWin.mjs', kind: 'wild_trigger_hold_and_win', knob: 'wildSymbolId', val: 'WX' },
  { mod: 'megaWildCluster.mjs',      kind: 'mega_wild_cluster',      knob: 'wildSymbol',   val: 'WX' },
  { mod: 'walkingWildStepper.mjs',   kind: 'walking_wild_stepper',   knob: 'wildSymbol',   val: 'WX' },
];

for (const tc of FEATURE_INHERIT_CASES) {
  await test(`P2 ${tc.mod}: features[].config inherits ${tc.knob}`, async () => {
    const mod = await import(resolve(REPO, 'src/blocks', tc.mod));
    const cfg = mod.resolveConfig({
      features: [{ kind: tc.kind, config: { [tc.knob]: tc.val } }],
    });
    assert(cfg.enabled === true, `enabled flip failed for kind=${tc.kind}`);
    assert(cfg[tc.knob] === tc.val,
      `expected ${tc.knob}='${tc.val}', got '${cfg[tc.knob]}'`);
  });
}

/* ────────────────────────────────────────────────────────────────────── */
/* P3 — H&W gate present in three new blocks. */

await test('P3 wildCollisionMultiplier: H&W gate present in _annotate', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/wildCollisionMultiplier.mjs'), 'utf8');
  assert(/if \(window\.HW_STATE && window\.HW_STATE\.active === true\) return/.test(src),
    'HW_STATE gate missing in _annotate');
});

await test('P3 cascadingWildPersistence: _hwActive wraps all listeners', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/cascadingWildPersistence.mjs'), 'utf8');
  assert(src.includes('function _hwActive()'), '_hwActive helper missing');
  assert(/if \(_hwActive\(\)\) return/.test(src), '_hwActive gate not wired');
});

await test('P3 mysteryWildReveal: H&W gate present in _scanAndReveal', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/mysteryWildReveal.mjs'), 'utf8');
  assert(/if \(window\.HW_STATE && window\.HW_STATE\.active === true\) return/.test(src),
    'HW_STATE gate missing in _scanAndReveal');
});

