  const src = readFileSync(resolve(REPO, 'src/blocks/fsExpansionWilds.mjs'), 'utf8');
  assert(src.includes("setAttribute('data-symbol'"), 'data-symbol setAttribute missing');
  assert(src.includes('window.GRID.set'), 'window.GRID.set missing');
  assert(/window\.HookBus\.emit\('symbolOverride'/.test(src), 'symbolOverride emit missing');
