/* ────────────────────────────────────────────────────────────────────── */
/* P5 — DOM fallback when grid arg missing (fsExpansionWilds). */

await test('P5 fsExpansionWilds: DOM fallback in _scanGridForWilds', async () => {
  const src = readFileSync(resolve(REPO, 'src/blocks/fsExpansionWilds.mjs'), 'utf8');
  assert(src.includes('document.querySelectorAll'), 'DOM fallback querySelectorAll missing');
  assert(src.includes("'[data-reel]'"), '[data-reel] selector missing');
});

/* ────────────────────────────────────────────────────────────────────── */
/* E2E: rebuilt Cash Eruption HTML contains the UQ-DEEP-Q fix. */

await test('E2E: Cash Eruption rebuilt HTML contains _expWildHwActive gate', async () => {
  const html = readFileSync(
    resolve(REPO, 'dist/ingest/cash-eruption-foundry-gdd/index.html'), 'utf8');
  assert(html.includes('_expWildHwActive'),
    'H&W gate missing in rebuilt Cash Eruption — rebuild dist');
  assert(html.includes('onReelsMutated'),
    'onReelsMutated event missing in rebuilt Cash Eruption');
  assert(/EXPANDING_WILD_APPLIES_ON_REELS_RAW\s*=\s*\[2,3,4,5\]/.test(html),
    'appliesOnReels [2,3,4,5] not propagated to Cash Eruption runtime');
  assert(html.includes('EXPANDING_WILD_ONLY_IF_WINNING = true'),
    'onlyIfWinning=true missing in Cash Eruption runtime');
});

/* ────────────────────────────────────────────────────────────────────── */
/* Source-precedence test: top-level model.xxxWild.* must still win over
 * features[].config (no regression of explicit-override semantics). */

await test('SOURCE PRECEDENCE stickyWild: top-level beats features[].config', async () => {
  const mod = await import(resolve(REPO, 'src/blocks/stickyWild.mjs'));
  const cfg = mod.resolveConfig({
    stickyWild: { wildSymbolId: 'TopLvl' },
    features: [{ kind: 'sticky_wild', config: { wildSymbolId: 'FromFeat' } }],
  });
  assert(cfg.wildSymbolId === 'TopLvl',
    `top-level should win, got: ${cfg.wildSymbolId}`);
});

await test('SOURCE PRECEDENCE walkingWild: top-level beats features[].config', async () => {
  const mod = await import(resolve(REPO, 'src/blocks/walkingWild.mjs'));
  const cfg = mod.resolveConfig({
    walkingWild: { wildSymbolId: 'TopLvl' },
    features: [{ kind: 'walking_wild', config: { wildSymbolId: 'FromFeat' } }],
  });
  assert(cfg.wildSymbolId === 'TopLvl',
    `top-level should win, got: ${cfg.wildSymbolId}`);
});

/* ────────────────────────────────────────────────────────────────────── */

console.log('');
console.log(`═══ ${pass} PASS · ${fail} FAIL ═══`);
if (fail > 0) {
  console.log('\nFailures:');
  for (const f of failures) console.log(`  ✗ ${f.name}\n      ${f.error}`);
  process.exit(1);
}
process.exit(0);
